import { Routes, Route } from "react-router-dom";
import Home from "./components/home";
import Booking from "./components/booking";

export default function App() {
  return (
    <Routes>
      <Route path="/" element={<Home />} />
      <Route path="/reservation" element={<Booking />} />
    </Routes>
  );
}
